def settle(expenses, prior_debts):
    bal = {}
    for e in expenses:
        bal[e["payer"]] = bal.get(e["payer"], 0) + e["amount"]
        per = e["amount"] / len(e["participants"])
        for p in e["participants"]:
            bal[p] = bal.get(p, 0) - per
    for d, c, amt in prior_debts:
        bal[d] = bal.get(d, 0) - amt
        bal[c] = bal.get(c, 0) + amt
    return {p: round(v, 2) for p, v in bal.items()}
